using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    // --- CalculateTotal: happy-path data-driven tests ---

    [TestMethod]
    [DynamicData(nameof(CalculateTotalData))]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);
        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate, decimal expected)> CalculateTotalData =>
    [
        (10m, 1, 0m, 10m),             // no tax, single item
        (10m, 5, 0m, 50m),             // no tax, multiple items
        (10m, 1, 0.1m, 11m),           // 10 % tax
        (25m, 4, 0.2m, 120m),          // 20 % tax, multiple items
        (0m, 10, 0.5m, 0m),            // zero price
        (100m, 0, 0.1m, 0m),           // zero quantity
        (99.99m, 1, 1m, 199.98m),      // 100 % tax (boundary)
    ];

    // --- CalculateTotal: invalid-argument tests ---

    [TestMethod]
    public void CalculateTotal_NegativeQuantity_ThrowsArgumentOutOfRange()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, -1, 0.1m));
        Assert.AreEqual("quantity", ex.ParamName);
    }

    [TestMethod]
    public void CalculateTotal_NegativeUnitPrice_ThrowsArgumentOutOfRange()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(-5m, 1, 0.1m));
        Assert.AreEqual("unitPrice", ex.ParamName);
    }

    [TestMethod]
    [DynamicData(nameof(InvalidTaxRates))]
    public void CalculateTotal_InvalidTaxRate_ThrowsArgumentOutOfRange(decimal taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, taxRate));
        Assert.AreEqual("taxRate", ex.ParamName);
    }

    public static IEnumerable<(decimal taxRate,)> InvalidTaxRates =>
    [
        (-0.01m,),
        (1.01m,),
    ];

    // --- ApplyDiscount: happy-path data-driven tests ---

    [TestMethod]
    [DynamicData(nameof(ApplyDiscountData))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);
        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> ApplyDiscountData =>
    [
        (100m, 10m, 90m),
        (200m, 25m, 150m),
        (50m, 0m, 50m),        // no discount
        (80m, 100m, 0m),       // full discount
        (99.99m, 50m, 49.995m),
    ];

    // --- ApplyDiscount: invalid-argument tests ---

    [TestMethod]
    [DataRow(-1)]
    [DataRow(101)]
    public void ApplyDiscount_InvalidDiscountPercent_ThrowsArgumentOutOfRange(int discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, discountPercent));
    }

    // --- FormatPrice ---

    [TestMethod]
    [DataRow(19.99, "$", "$19.99")]
    [DataRow(5, "€", "€5.00")]
    [DataRow(1234.5, "£", "£1234.50")]
    public void FormatPrice_WithCurrencySymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPrice_DefaultSymbol_UsesDollarSign()
    {
        var result = _calculator.FormatPrice(42m);
        Assert.AreEqual("$42.00", result);
    }
}

